// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "forge-std/Test.sol";

import "contracts/USDe.sol";
import "contracts/StakedUSDe.sol";
import "contracts/interfaces/IStakedUSDe.sol";

contract INV_ERC4626_WITHDRAW_PREVIEW_UPPER_BOUND_Test is Test {
    address internal admin = address(this);
    address internal rewarder = address(this);
    address internal alice = address(0xA11CE);

    function _deployStakedUSDe() internal returns (USDe usde, StakedUSDe vault) {
        usde = new USDe(admin);
        usde.setMinter(admin);

        vault = new StakedUSDe(IERC20(address(usde)), rewarder, admin);

        // fund alice
        usde.mint(alice, 10 ether);

        vm.startPrank(alice);
        usde.approve(address(vault), type(uint256).max);
        vm.stopPrank();
    }

    /// @dev Violation: previewWithdraw suggests a 1-wei withdrawal costs 1 share,
    /// but withdraw reverts due to MinSharesViolation when totalSupply would drop below MIN_SHARES.
    function test_previewWithdraw_underestimates_withdraw_feasibility_dueToMinShares() public {
        (USDe usde, StakedUSDe vault) = _deployStakedUSDe();

        // Deposit exactly MIN_SHARES worth of assets (1e18). Initial state totalAssets()==0,
        // so shares minted == assets == 1e18 and passes MIN_SHARES check.
        vm.startPrank(alice);
        vault.deposit(1 ether, alice);

        uint256 assetsToWithdraw = 1; // 1 wei USDe

        // In this state, previewWithdraw returns 1 share and maxWithdraw allows it.
        uint256 previewShares = vault.previewWithdraw(assetsToWithdraw);
        assertEq(previewShares, 1);
        assertGe(vault.maxWithdraw(alice), assetsToWithdraw);

        // But withdraw reverts because it would leave totalSupply in (0, MIN_SHARES).
        vm.expectRevert(IStakedUSDe.MinSharesViolation.selector);
        vault.withdraw(assetsToWithdraw, alice, alice);
        vm.stopPrank();

        // Sanity: state unchanged after revert
        assertEq(vault.balanceOf(alice), 1 ether);
        assertEq(usde.balanceOf(alice), 9 ether);
    }

    /// @dev Control: for sufficiently large totalSupply, withdraw succeeds and equals previewWithdraw.
    function test_withdraw_sharesEqualsPreviewWithdraw_whenNoMinSharesViolation() public {
        (, StakedUSDe vault) = _deployStakedUSDe();

        vm.startPrank(alice);
        vault.deposit(2 ether, alice);

        uint256 assetsToWithdraw = 1; // 1 wei
        uint256 previewShares = vault.previewWithdraw(assetsToWithdraw);

        uint256 sharesBefore = vault.balanceOf(alice);
        uint256 sharesReturned = vault.withdraw(assetsToWithdraw, alice, alice);
        uint256 sharesAfter = vault.balanceOf(alice);

        assertEq(sharesReturned, previewShares);
        assertEq(sharesBefore - sharesAfter, sharesReturned);
        vm.stopPrank();
    }
}
